#include <torch/torch.h>

#define TILE_SIZE 16

__global__ void bmm_with_relu(torch::Tensor A, torch::Tensor B, torch::Tensor C) {
    int batch = blockIdx.x;
    int m = blockIdx.y * TILE_SIZE + threadIdx.y;
    int n = blockIdx.z * TILE_SIZE + threadIdx.z;

    float c[TILE_SIZE][TILE_SIZE] = {0};

    for (int k = 0; k < A.size(2); k += TILE_SIZE) {
        __shared__ float a_shared[TILE_SIZE][TILE_SIZE];
        __shared__ float b_shared[TILE_SIZE][TILE_SIZE];

        int a_row = blockIdx.y * TILE_SIZE + threadIdx.y;
        int a_col = blockIdx.z * TILE_SIZE + k;
        int b_col = blockIdx.x * TILE_SIZE + threadIdx.z;

        // Load A into shared memory
        if (a_row < A.size(1) && a_col < A.size(2)) {
            a_shared[threadIdx.y][threadIdx.z] = A[batch][a_row][a_col];
        } else {
            a_shared[threadIdx.y][threadIdx.z] = 0;
        }

        // Load B into shared memory
        if (b_row < B.size(1) && b_col < B.size(2)) {
            b_shared[threadIdx.y][threadIdx.z] = B[batch][b_row][b_col];
        } else {
            b_shared[threadIdx.y][threadIdx.z] = 0;
        }

        __syncthreads();

        // Perform matrix multiplication
        for (int i = 0; i < TILE_SIZE; ++i) {
            for (int j = 0; j < TILE_SIZE; ++j) {
                c[threadIdx.y][threadIdx.z] += a_shared[i][threadIdx.z] * b_shared[threadIdx.y][j];
            }
        }

        __syncthreads();
    }

    // Store result with ReLU
    if (m < C.size(1) && n < C.size(2)) {
        C[batch][m][n] = max(c[threadIdx.y][threadIdx.z], 0.0f);
    }
}

torch::Tensor bmm_with_relu_cuda(torch::Tensor A, torch::Tensor B) {
    auto options = torch::TensorOptions().dtype(torch::kFloat32);
    auto C = torch::zeros({A.size(0), A.size(1), B.size(2)}, options);

    dim3 blocks(A.size(0), (A.size(1) + TILE_SIZE - 1) / TILE_SIZE, (B.size(2) + TILE_SIZE - 1) / TILE_SIZE);
    dim3 threads(TILE_SIZE, TILE_SIZE);

    bmm_with_relu<<<blocks, threads>>>(A, B, C);

    return C;
