import torch
import torch.nn as nn
from torch.utils.cpp_extension import load_inline

cpp_sources = r"""
#include <ATen/core/Tensor.h>
#include <ATen/native/CUDAUtils.h>

void fused_matmul(const at::Tensor& A, const at::Tensor& B, at::Tensor& C) {
    int M = A.size(0);
    int K = A.size(1);
    int N = B.size(1);

    AT_DISPATCH_FLOATING_TYPES(A.type(), "fused_matmul", [&] {
        auto* A_data = A.data_ptr<scalar_t>();
        auto* B_data = B.data_ptr<scalar_t>();
        auto* C_data = C.data_ptr<scalar_t>();

        for (int m = 0; m < M; ++m) {
            for (int n = 0; n < N; ++n) {
                scalar_t sum = 0;
                for (int k = 0; k < K; ++k) {
                    sum += A_data[m * K + k] * B_data[k * N + n];
                }
                C_data[m * N + n] = sum;
            }
        }
    });
}
"""

cuda_sources = r"""
#include <cuda_runtime.h>
#include <cublas_v2.h>

extern "C" void fused_matmul_cuda(const float* A, const float* B, float* C, int M, int K, int N) {
    cublasHandle_t handle;
    CHECK_CUDA(cudaStream_t stream = c10::cuda::getCurrentCUDAStream());
    CHECK_CUDA(cublasCreate(&handle));
    CHECK_CUDA(cublasSetStream(handle, stream));

    float alpha = 1.0f, beta = 0.0f;
    CHECK_CUDA(cublasSgemm(handle, CUBLAS_OP_N, CUBLAS_OP_N, M, N, K, &alpha, A, K, B, N, &beta, C, N));

    CHECK_CUDA(cublasDestroy(handle));
}
"""

class ModelNew(nn.Module):
    def __init__(self):
        super(ModelNew, self).__init__()

    def forward(self, A, B):
        C = torch.zeros((A.size(0), B.size(1)), dtype=A.dtype, device=A.device)
        if A.device.type == 'cpu':
            fused_matmul(A, B, C)
        else:
            fused_matmul_cuda(A.contiguous().view(-1).cpu().numpy(), B.contiguous().view(-1).cpu().numpy(), C.view(-1).cpu().numpy(), A.size(0), A.size(1), B.size(1))
            C = C.to(A.device)
        return C

def get_inputs():
    A = torch.rand(16384 * 2, 16 * 2)
    B = torch.rand(16 * 2, 16384 * 2)
    return [A, B]

def get_init_inputs():
    return []
