#include <iostream>
#include <vector>

struct Tensor {
    float* data;
    int size[4];
};

__global__ void mish_fused_kernel(float* input, float* output, int n) {
    int idx = blockIdx.x * blockDim.x + threadIdx.x;
    if (idx < n) {
        float val = input[idx];
        float exp_val = expf(-val);
        output[idx] = val * (exp_val + 1) / (exp_val + 2);
    }
}

void mish_fused(Tensor input, Tensor output) {
    int n = input.size[0] * input.size[1] * input.size[2] * input.size[3];
    dim3 blocks((n + 255) / 256);
    dim3 threads(256);
    mish_fused_kernel<<<blocks, threads>>>(input.data, output.data, n);
}
