at::Tensor softmax_with_bias(const at::Tensor& input, const at::Tensor& bias) {
    CHECK_CUDA(input);
    CHECK_CONTIGUOUS(input);
    CHECK_CUDA(bias);
    CHECK_CONTIGUOUS(bias);

