    for (int n = 0; n < batch_size; ++n) {
        for (int c = 0; c < channels; ++c) {
            float* input_ptr = input.data_ptr<float>() + n * channels * depth * height * width + c * depth * height * width;
            float* bias_ptr = bias.data_ptr<float>() + c * depth * height * width;
