#include <torch/extension.h>

void relu_bias_scale_clamp(torch::Tensor input, torch::Tensor output, float bias, float scale, float clamp_min, float clamp_max) {
    const int numel = input.numel();
    for (int i = 0; i < numel; ++i) {
        float val = input[i] + bias;
        val *= scale;
        if (val < clamp_min) {
            output[i] = clamp_min;
        } else if (val > clamp_max) {
            output[i] = clamp_max;
        } else {
            output[i] = val;
        }
    }
}
"""

