#include <torch/extension.h>
#include <cublas_v2.h>

__global__ void gemm_relu_bias_scale_clamp(float* a, float* b, float* c, float* d, float bias, float scale, float clamp_min, float clamp_max, int m, int n, int k) {
    extern __shared__ float sdata[];
    int row = blockIdx.y * blockDim.y + threadIdx.y;
    int col = blockIdx.x * blockDim.x + threadIdx.x;

    float sum = 0.0f;
    if (row < m && col < n) {
        for (int i = 0; i < k; ++i) {
            sum += a[row * k + i] * b[i * n + col];
        }
        sum += bias;
        sum *= scale;
        if (sum < clamp_min) {
            d[row * n + col] = clamp_min;
        } else if (sum > clamp_max) {
            d[row * n + col] = clamp_max;
        } else {
            d[row * n + col] = sum;
        }
    }
}

torch::Tensor custom_gemm_relu_bias_scale_clamp(const torch::Tensor& a, const torch::Tensor& b, float bias, float scale, float clamp_min, float clamp_max) {
    auto options = torch::TensorOptions().dtype(a.dtype()).device(a.device());
    auto c = torch::zeros({a.size(0), b.size(1)}, options);
    auto d = torch::zeros_like(c);

    cublasHandle_t handle;
    CHECK_CUBLAS(cublasCreate(&handle));

    int m = a.size(0), n = b.size(1), k = a.size(1);
    float alpha = 1.0f, beta = 0.0f;

    CHECK_CUBLAS(cublasSgemm(handle, CUBLAS_OP_N, CUBLAS_OP_N, n, m, k, &alpha, b.data_ptr<float>(), k, a.data_ptr<float>(), k, &beta, d.data_ptr<float>(), n));

    relu_bias_scale_clamp(d, c, bias, scale, clamp_min, clamp_max);

    cublasDestroy(handle);

    return c;
}
