#include <torch/torch.h>

std::tuple<torch::Tensor, torch::Tensor> bn_relu_fused(const torch::Tensor& x, const torch::Tensor& gamma, const torch::Tensor& beta, float eps) {
    auto mean = torch::mean(x, {0, 2, 3}, true);
    auto var = torch::var_mean(x, {0, 2, 3}, true)[1];
    auto inv_var = torch::rsqrt(var + eps);
    auto normalized = (x - mean) * inv_var;
    auto scaled = normalized * gamma;
